+            (e, sink) -> Stream.empty().forEach(i -> sink.accept((Integer) i));
+    BiConsumer<Integer, Consumer<Integer>> intRangeConsumer =
+            (e, sink) -> IntStream.range(0, e).boxed().forEach(sink);
